INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('31-data-os',3,31,'DATA OS','He dieu hanh du lieu',31,'draft','2026-06-20T16:43:36Z','2026-06-20T16:43:36Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('51edfe81-c984-448a-8bee-2c2cc8466091','31-data-os',NULL,2,'31.1 DATA OS là gì?','311-data-os-la-gi',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b58d025a-e17f-4ede-9b21-83720bc124d5','51edfe81-c984-448a-8bee-2c2cc8466091',0,'text','Trong y khoa, trước khi tiến hành bất kỳ ca phẫu thuật Implant hay chỉnh nha chuyên sâu nào, việc đầu tiên của ekip là cắm các cổng cảm biến để đo **chỉ số sinh tồn (Vital Signs)** của bệnh nhân: mạch đập, huyết áp, nhịp thở và nồng độ SpO_2. Nếu các chỉ số này nằm ngoài biên độ an toàn, lệnh hoãn ca sẽ được phát ra lập tức để bảo vệ tính mạng con người. Không một bác sĩ nào dám hạ dao mổ chỉ dựa vào cảm giác *"nhìn sắc mặt bệnh nhân thấy có vẻ ổn"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3ab3461-0ef6-404e-b740-87a668597a1f','51edfe81-c984-448a-8bee-2c2cc8466091',1,'text','Thế nhưng, khi bước vào phòng điều hành, phần lớn các chủ phòng khám răng hàm mặt lại đang quản trị tổ chức của mình bằng chính cái bẫy "sắc mặt" đó. Họ thấy sảnh chờ nhộn nhịp thì nghĩ phòng khám đang khỏe mạnh; nghe nhân viên báo cáo *"tháng này bận rộn lắm"* thì tin rằng bộ máy đang chạy tốt. Đây chính là lỗ hổng chí mạng dẫn đến những ca "đột quỵ tài chính" hoặc "sốc phản vệ vận hành" mà không hề được cảnh báo trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85e4718c-f29a-4651-952f-1037a82de303','51edfe81-c984-448a-8bee-2c2cc8466091',2,'text','Trong kiến trúc **Dental Empire**, **Data OS** không đơn thuần là một kho lưu trữ số liệu Excel khô khan. Hệ điều hành này đóng vai trò là **Hệ thống monitor theo dõi chỉ số sinh tồn của tổ chức**. Dữ liệu sạch truyền về liên tục từ CRM, Finance OS và People OS chính là những nhịp mạch, điện tâm đồ phản ánh chính xác 100% tình trạng sức khỏe thực tế của phòng khám theo từng giờ, từng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78eb89e5-0570-4e34-bfd1-5adf44c9745e','51edfe81-c984-448a-8bee-2c2cc8466091',3,'text','**Mắt Xích Kết Nối Giữa Vận Hành Con Người Và Số Liệu Thực Chứng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d018d5b-fe52-4a9d-9975-639a51fbfe08','51edfe81-c984-448a-8bee-2c2cc8466091',4,'text','Mối quan hệ tương hỗ giữa các hệ điều hành này quyết định tốc độ và sự an toàn của phòng khám trên hành trình bứt phá quy mô:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29af5321-2e1a-40bf-bdd2-3dbad63a6470','51edfe81-c984-448a-8bee-2c2cc8466091',5,'text','Con người tạo ra hành động, nhưng chỉ có dữ liệu mới phản ánh được bản chất và hiệu quả thực tế của hành động đó. Khi Data OS được ráp nối khít khao với People OS, chủ phòng khám sẽ sở hữu một "phim chụp X-quang vận hành" sắc nét, hiển thị rõ mồn một từng chỉ số chuyển đổi của sảnh chờ và phòng điều trị mà không cần phải có mặt để giám sát thủ công.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d761f5fc-f31a-49c1-bc02-224555eb0b5c','51edfe81-c984-448a-8bee-2c2cc8466091',6,'text','**Mantra chuyển giao phân hệ:***"Con người có thể che giấu hiệu suất bằng cảm xúc hoặc các báo cáo định tính, nhưng các con số sạch trên Dashboard thì không biết thỏa hiệp. Hãy dùng Data OS làm cây thước đo lường sòng phẳng năng lực của hệ thống nhân sự, biến mọi điểm chạm tại phòng khám thành những tài sản dữ liệu có khả năng dẫn đường cho chiến lược."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fb39f7a8-1ed2-408e-ae5f-2233ad3e174f','31-data-os','51edfe81-c984-448a-8bee-2c2cc8466091',3,'Tư Duy Quản Trị: Xóa Bỏ Kỷ Nguyên "Tôi Nghĩ", "Tôi Cảm Thấy" Trong Điều Hành','tu-duy-quan-tri-xoa-bo-ky-nguyen-toi-nghi-toi-cam-thay-trong-ieu-hanh',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05c50db8-b4ea-4b26-b104-1aeefcefe9c4','fb39f7a8-1ed2-408e-ae5f-2233ad3e174f',7,'text','Căn bệnh nguy hiểm nhất của một chủ phòng khám răng hàm mặt khi bước từ vai trò bác sĩ thuần túy lên làm nhà quản lý là thói quen ra quyết định dựa trên trực giác và cảm tính. Nhiều chủ phòng khám chỉ cần nhìn sảnh chờ đông đúc một vài ngày đã vội vã đầu tư thêm ghế nha công nghệ cao; hoặc chỉ vì một tuần lượng khách sụt giảm đã lập tức ra lệnh thay đổi toàn bộ đội ngũ tiếp thị. Việc điều hành dựa trên trạng thái cảm xúc ngắn hạn như vậy giống như một phi công lái máy bay xuyên qua bão mà không thèm nhìn bảng đồng hồ hiển thị thông số.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('082b3eb9-c984-4e1a-bedd-60df476e2a60','fb39f7a8-1ed2-408e-ae5f-2233ad3e174f',8,'text','Trong kiến trúc tổng thể của **Dental Empire**, **Data OS** đóng vai trò là **hệ thần kinh trung ương**. Hệ điều hành này chịu trách nhiệm thu thập, làm sạch, phân tích và chuyển hóa toàn bộ các dữ liệu thô từ thực địa lâm sàng và kinh doanh thành những thông tin có khả năng dẫn đường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4be63eef-2f72-453f-9745-a5ab4367d5db','fb39f7a8-1ed2-408e-ae5f-2233ad3e174f',9,'text','Data OS thiết lập một kỷ luật quản trị tối cao: **Mọi quyết định kinh doanh hoặc điều chỉnh vận hành đều phải được chứng minh bằng dữ liệu thực tế.** Nếu không có số liệu sạch để đối soát, mọi ý kiến trong phòng họp đều vô giá trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('893f0530-ff44-4c17-bb89-2c76770faac7','fb39f7a8-1ed2-408e-ae5f-2233ad3e174f',10,'text','- **Ma Trận Chuyển Dịch: Quản Trị Cảm Tính Vs. Quản Trị Thực Chứng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('755fabd4-e38b-49a7-9a9e-b1b9c990bc3b','fb39f7a8-1ed2-408e-ae5f-2233ad3e174f',11,'text','Để xây dựng một chuỗi nha khoa bền vững và có khả năng nhân bản, tư duy của ban giám đốc bắt buộc phải dịch chuyển qua bộ màng lọc dữ liệu dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cd8a192-82e2-4f0f-ba09-1797a9ff12c9','fb39f7a8-1ed2-408e-ae5f-2233ad3e174f',12,'image',NULL,'book/31-data-os/09d295b5-b091-4bc4-b2f5-8b2c9b5bc8aa-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('096b5472-eaa8-4e17-b76a-aefb0cb94c69','31-data-os','51edfe81-c984-448a-8bee-2c2cc8466091',3,'Bốn Tầng Kiến Trúc Của Hệ Thống Data OS','bon-tang-kien-truc-cua-he-thong-data-os',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('200b570b-faa3-4ab6-a45f-7e6cb9f5c8e2','096b5472-eaa8-4e17-b76a-aefb0cb94c69',13,'image',NULL,'book/31-data-os/429b7e85-d73f-4c26-8fc2-43aaa92dab40-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f6f89e1f-2dfb-42ed-8092-00c464799baa','096b5472-eaa8-4e17-b76a-aefb0cb94c69',14,'text','- **Thu thập (Data Collection):** Cắm mắt xích đo lường vào mọi điểm chạm của khách hàng. Ghi nhận thời gian thực từ lúc bệnh nhân nhìn thấy nội dung truyền thông, để lại thông tin, đặt lịch hẹn, đến sàn, ký phác đồ, chụp X-quang cho đến khâu hậu phẫu.- **Chuẩn hóa (Data Normalization):** Ép dữ liệu vào các định dạng quy chuẩn. Loại bỏ hồ sơ trùng lặp, xử lý các trường thông tin sai lệch do nhập liệu thủ công, đảm bảo tính đồng nhất của hệ thống dữ liệu giữa khối sảnh và khối lâm sàng.- **Quản trị (Data Governance):** Thiết lập ranh giới bảo mật nghiêm ngặt. Phân quyền truy cập dữ liệu theo cấp bậc (Lễ tân chỉ nhìn thấy lịch hẹn, TCO nhìn thấy phác đồ tài chính, Bác sĩ nhìn thấy hồ sơ bệnh án chuyên môn). Tuyệt đối chặn đứng nguy cơ rò rỉ thông tin bệnh nhân ra ngoài thị trường.- **Sử dụng (Data Utilization):** Chuyển hóa các bảng tính Excel phức tạp thành các biểu đồ trực quan (Dashboard) thời gian thực. Giúp chủ phòng khám nhìn thấy ngay lập tức "bệnh lý vận hành" của cơ sở để đưa ra quyết định xử lý trong vòng 5 phút.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cfcfc7f0-94ed-4821-9aa3-0568d7d59e38','31-data-os','51edfe81-c984-448a-8bee-2c2cc8466091',3,'Chỉ Số Toàn Vẹn Dữ Liệu Hệ Thống (DII)','chi-so-toan-ven-du-lieu-he-thong-dii',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f815dfa3-9289-413a-85d8-c9f8be38a65b','cfcfc7f0-94ed-4821-9aa3-0568d7d59e38',15,'image',NULL,'book/31-data-os/c9fe8488-9105-43c4-afb6-7821a1b09235-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b93a6297-e37d-4ca4-af2a-142e2e117e45','cfcfc7f0-94ed-4821-9aa3-0568d7d59e38',16,'text','**Mantra điều hành Data OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bacf233-2f2a-4e6e-bed9-a1a175fcaab0','cfcfc7f0-94ed-4821-9aa3-0568d7d59e38',17,'text','*"Trong y khoa lâm sàng, chúng ta chỉ tin vào bằng chứng thực chứng và phim chụp X-quang để đưa ra phác đồ điều trị. Trong quản trị nha khoa cũng vậy, hãy tuyệt đối trung thành với dữ liệu thực chứng. Đừng nói với tôi các giả định hay cảm giác của bạn, hãy cho tôi nhìn thấy những con số sạch trên Dashboard."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c76b3905-da4f-4f86-bbd4-5424eff763e7','31-data-os',NULL,2,'31.2 Vai Trò Chiến Lược Của Data OS - Đồng Bộ Một Sự Thật Toàn Diện','312-vai-tro-chien-luoc-cua-data-os-ong-bo-mot-su-that-toan-dien',4,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('34966af8-f898-42f0-81ce-01c8c7ac888a','31-data-os','c76b3905-da4f-4f86-bbd4-5424eff763e7',3,'Đập Tan Trò Chơi Đổ Lỗi Liên Phòng Ban (Anti-Silos Crusher)','ap-tan-tro-choi-o-loi-lien-phong-ban-anti-silos-crusher',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03318e97-2e4a-49f4-af44-686a88fbe876','34966af8-f898-42f0-81ce-01c8c7ac888a',18,'text','Khi phòng khám nha khoa bắt đầu bứt phá quy mô, một hiện tượng nguy hiểm sẽ tự động xuất hiện: **Sự cát cứ thông tin (Silos)**. Khi không có một hệ thống đối soát dữ liệu tập trung, các bộ phận sẽ vận hành hoàn toàn rời rạc và có xu hướng đổ lỗi chéo để bảo vệ lợi ích cục bộ của phòng ban mình khi mục tiêu tài chính tối cao không đạt:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('859a657a-96e6-4e3a-a855-fc86026f578f','34966af8-f898-42f0-81ce-01c8c7ac888a',19,'text','- **Bộ phận Marketing** tự hào báo cáo: *"Tháng này chạy chiến dịch rất tốt, mang về hàng nghìn Lead giá rẻ."*- **Bộ phận Sales (TCO)** lập tức phản pháo: *"Lead nhiều nhưng toàn data rác, gọi điện không bắt máy, tỷ lệ đặt lịch không có."*- **Khối Lâm sàng (Clinic)** phàn nàn: *"Khách đến sàn không đúng tệp, nhu cầu không phù hợp với năng lực điều trị chuyên sâu của phòng khám."*- **Bộ phận Tài chính (Finance)** kết luận: *"Doanh thu thực thu cuối tháng vẫn không đủ bù đắp chi phí vận hành."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39d2ee2a-5424-49de-a272-1816e2dc2fa3','34966af8-f898-42f0-81ce-01c8c7ac888a',20,'text','**Data OS** xuất hiện để chấm dứt vĩnh viễn cuộc khủng hoảng truyền thông nội bộ này. Hệ điều hành dữ liệu ép tất cả các phòng ban từ Marketing, Sales, Lâm sàng cho đến Tài chính phải ngồi lại với nhau và **nhìn vào cùng một sự thật khách quan duy nhất**. Dữ liệu sạch từ Data OS loại bỏ hoàn toàn các nhận định cảm tính, buộc các bộ phận phải chịu trách nhiệm dựa trên các con số đối soát liên hoàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0cbb9e43-d61d-46d7-961e-33831c170b4b','31-data-os','c76b3905-da4f-4f86-bbd4-5424eff763e7',3,'Bảng Đối Soát: Xóa Bỏ Xung Đột Bằng Dữ Liệu Đồng Nhất','bang-oi-soat-xoa-bo-xung-ot-bang-du-lieu-ong-nhat',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('59f26086-9608-4bd3-bd44-acd80175595e','0cbb9e43-d61d-46d7-961e-33831c170b4b',21,'image',NULL,'book/31-data-os/e79d952c-e2f5-4703-879e-d6c5eeee76f1-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5f16cf55-f97d-4dea-977a-54464230048f','31-data-os','c76b3905-da4f-4f86-bbd4-5424eff763e7',3,'Truy Vết Toàn Diện Hành Trình Tăng Trưởng (Full-Funnel Data Pipeline)','truy-vet-toan-dien-hanh-trinh-tang-truong-full-funnel-data-pipeline',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('375f2f25-89d9-4dcf-9742-38b41e559c46','5f16cf55-f97d-4dea-977a-54464230048f',22,'text','Data OS giúp người điều hành phòng khám không bỏ sót bất kỳ một tín hiệu cảnh báo nào trên bản đồ tăng trưởng thông qua một đường ống dữ liệu tuyến tính, khép kín từ điểm chạm truyền thông đầu tiên cho đến dòng tiền lợi nhuận cuối cùng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6f611686-a446-4581-acf3-5b637ee437e1','31-data-os','5f16cf55-f97d-4dea-977a-54464230048f',4,'Chặng 1: Thu hút dữ liệu - Content ➔ Lead:','chang-1-thu-hut-du-lieu-content-lead',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a9976ec-0a0d-4032-9db9-c3b3c4e4c614','6f611686-a446-4581-acf3-5b637ee437e1',23,'text','Hệ thống ghi nhận số lượng bài viết, video xuất bản và đo lường chính xác lượng hồ sơ khách hàng thô (Lead) thu về trên mỗi kênh nội dung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ba85cc6e-2030-4e70-a301-0d96af786c03','31-data-os','5f16cf55-f97d-4dea-977a-54464230048f',4,'Chặng 2: Kích hoạt điểm hẹn - Booking ➔ Show-up:','chang-2-kich-hoat-iem-hen-booking-show-up',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9d8eb38-383f-4431-af04-7a8fd05d6889','ba85cc6e-2030-4e70-a301-0d96af786c03',24,'text','Đo lường năng lực của telesale thông qua tỷ lệ chuyển đổi từ dữ liệu thô sang lịch hẹn (Booking) và tỷ lệ khách đặt chân đến sảnh thực tế (Show-up).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('621b7800-2016-4139-8eb7-b675a7162293','31-data-os','5f16cf55-f97d-4dea-977a-54464230048f',4,'Chặng 3: Chuyển đổi lâm sàng - Consultation ➔ Treatment:','chang-3-chuyen-oi-lam-sang-consultation-treatment',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc1ab43e-ae8f-4ee7-b43d-f9e997d54ac5','621b7800-2016-4139-8eb7-b675a7162293',25,'text','Truy vết hiệu suất của bác sĩ và chuyên viên tư vấn ngay tại phòng khám: Có bao nhiêu ca khám sàng lọc (Consultation) chuyển hóa thành ca đồng ý can thiệp phác đồ điều trị (Treatment).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('41c12f65-0764-4e19-a129-a4d57bd1f419','31-data-os','5f16cf55-f97d-4dea-977a-54464230048f',4,'Chặng 4: Kích nổ bánh đà - Patient Experience ➔ Review ➔ Referral:','chang-4-kich-no-banh-a-patient-experience-review-referral',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f27b583-9946-40d4-91b2-232746158994','41c12f65-0764-4e19-a129-a4d57bd1f419',26,'text','Số hóa mức độ hài lòng của bệnh nhân (Patient\\ Experience) sau thủ thuật để tự động kích hoạt kịch bản xin đánh giá 5 sao (Review) và khai thác nguồn khách giới thiệu (Referral).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('04692f7d-ec8f-43cd-b894-05a7b990c145','31-data-os','5f16cf55-f97d-4dea-977a-54464230048f',4,'Chặng 5: Điểm kết tài chính - Revenue ➔ Profit:','chang-5-iem-ket-tai-chinh-revenue-profit',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c9e204d-eccd-4175-ad83-55459707e4c9','04692f7d-ec8f-43cd-b894-05a7b990c145',27,'text','Dữ liệu chuyển hóa thành dòng tiền mặt thực thu (Revenue) nạp về hệ thống kế toán và tự động khấu trừ chi phí để trích xuất ra lợi nhuận ròng (Profit).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1455984c-be0a-4fd7-b141-60ff5646f816','31-data-os','c76b3905-da4f-4f86-bbd4-5424eff763e7',3,'Chỉ Số Đồng Bộ Dữ Liệu Toàn Phễu (FAL)','chi-so-ong-bo-du-lieu-toan-pheu-fal',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6fff7346-9ac1-42a0-bee5-ff7b5a991920','1455984c-be0a-4fd7-b141-60ff5646f816',28,'text','Để kiểm soát xem đường ống dữ liệu có đang bị rò rỉ hoặc sai lệch thông tin giữa các bộ phận hay không, Data OS áp dụng công thức kiểm toán **Tỷ lệ thất thoát dữ liệu toàn phễu (Full-Funnel Data Leakage - ****FAL****)** hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53c496f8-137f-4b92-8e54-3e66e841df53','1455984c-be0a-4fd7-b141-60ff5646f816',29,'text','FAL (\\%) = \\left( 1 - \\frac{\\text{Số lượng hồ sơ bệnh nhân được đối soát trùng khớp 100\\% trên tất cả các chặng}}{\\text{Tổng số lượng Lead thô nạp vào hệ thống ban đầu}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('416d00f2-96b4-43c1-89d0-ef55c85de45b','1455984c-be0a-4fd7-b141-60ff5646f816',30,'text','- **Ngưỡng an toàn tối cao của hệ thống:** Chỉ số FAL bắt buộc phải kiểm soát ở mức **nhỏ hơn 5%**.- **Hành động sửa sai lập tức:** Nếu chỉ số FAL vượt ngưỡng 10%, điều này báo động hệ thống quản trị đang bị hổng nghiêm trọng: Nhân sự đang tự ý xóa data, bỏ quên không cập nhật trạng thái khách chưa chốt lên CRM, hoặc kế toán ghi nhận doanh thu lệch so với phác đồ lâm sàng. Quản trị viên dữ liệu (Data\\ Owner) phải lập tức khóa quyền xuất dữ liệu và tiến hành truy vết, làm sạch lại toàn bộ kho data trong vòng 24 giờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee85c0ec-3080-4c46-945c-8e34ad6a12db','1455984c-be0a-4fd7-b141-60ff5646f816',31,'image',NULL,'book/31-data-os/9b1fb551-cbf7-452d-9860-8e701447486f-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da3cf135-b10e-4ba2-88a0-fff8547a83e8','1455984c-be0a-4fd7-b141-60ff5646f816',32,'text','**Mantra điều hành vai trò Data OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('32a44aa2-89f8-4b67-8162-0943cdc2bb47','1455984c-be0a-4fd7-b141-60ff5646f816',33,'text','*"Khi mọi bộ phận cùng nhìn vào một bảng Dashboard dữ liệu sạch, trò chơi đổ lỗi sẽ kết thúc và kỷ luật thực thi sẽ lên ngôi. Đừng điều hành phòng khám bằng những lời giải thích hoa mỹ hay những lý do ngụy biện; hãy dùng dữ liệu thực chứng làm tiếng nói tối cao để dẫn đường cho mọi quyết định tăng trưởng."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('de55d357-1645-4cb0-a45b-0af782affe0c','31-data-os',NULL,2,'31.3 Các Nhóm Dữ Liệu Cốt Lõi Cần Quản Trị Trong Nha Khoa Tăng Trưởng','313-cac-nhom-du-lieu-cot-loi-can-quan-tri-trong-nha-khoa-tang-truong',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21d34c3b-58da-4489-a611-6090820b026d','de55d357-1645-4cb0-a45b-0af782affe0c',34,'text','Dữ liệu của một phòng khám nha khoa không đơn thuần là danh sách số điện thoại bệnh nhân hay một vài bảng tính doanh thu cuối tháng. Để hệ điều hành **Data OS** thực sự làm chủ được hành trình bứt phá quy mô, toàn bộ thông tin phát sinh trong quá trình vận hành phải được phân loại thành **8 nhóm dữ liệu cốt lõi**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3bff0a65-b0c1-4944-814f-bda453438501','de55d357-1645-4cb0-a45b-0af782affe0c',35,'text','Mỗi nhóm dữ liệu đại diện cho một mắt xích trong chuỗi giá trị của phòng khám, được liên thông chặt chẽ để tạo ra một bức tranh toàn cảnh về sức khỏe doanh nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cdd5552f-bbd6-44c3-b4a2-d44d352e7db2','31-data-os','de55d357-1645-4cb0-a45b-0af782affe0c',3,'Ma Trận Phân Loại Và Mục Tiêu Quản Trị 8 Nhóm Dữ Liệu Nha Khoa','ma-tran-phan-loai-va-muc-tieu-quan-tri-8-nhom-du-lieu-nha-khoa',15,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('279c05ae-2eb2-4767-8213-b65b2e8ff8e1','31-data-os','de55d357-1645-4cb0-a45b-0af782affe0c',3,'Chỉ Số Độ Đầy Đủ Và Sạch Của Kho Dữ Liệu (DCR)','chi-so-o-ay-u-va-sach-cua-kho-du-lieu-dcr',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d6faa81e-73a1-4317-9846-a7d729e2d31e','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',36,'text','Một kho dữ liệu chỉ có giá trị khi nó phản ánh đầy đủ và chính xác thực tế vận hành. Nếu nhân sự lười nhập liệu, bỏ trống các trường thông tin quan trọng (như bỏ quên nguồn khách, không ghi nhận lý do từ chối), dữ liệu trích xuất ra sẽ bị sai lệch hoàn toàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('386694e7-cc72-4c70-a4ea-4ecc11b5d441','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',37,'text','Để kiểm soát chất lượng đầu vào, Data OS sử dụng chỉ số **Tỷ lệ điền đầy dữ liệu quy chuẩn (Data Completeness Rate - ****DCR****)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d67f301-1579-4a5b-b4f1-1e8c3067e222','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',38,'text','DCR (\\%) = \\left( \\frac{\\text{Tổng số trường dữ liệu bắt buộc được điền ĐÚNG trong 8 nhóm}}{\\text{Tổng số trường dữ liệu tiêu chuẩn hệ thống yêu cầu cấu hình}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d624a46-4d9e-4981-b180-0aca202de501','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',39,'text','**Định mức kiểm toán chất lượng hạ tầng dữ liệu nha khoa:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ad88226-0f04-40cd-af46-3ea69736788c','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',40,'text','- **Ngưỡng Vùng Xanh (Hệ thống sạch):** Chỉ số DCR \\ge 95\\%. Đội ngũ nhập liệu chuẩn xác, Dashboard phản ánh đúng 100% bệnh lý vận hành của phòng khám để Ban điều hành ra phác đồ chiến lược.- **Hành động sửa sai:** Nếu chỉ số DCR tụt xuống dưới mức 85% tại bất kỳ bộ phận nào, Quản trị viên dữ liệu (Data\\ Owner) phải phát lệnh dừng nghiệm thu hiệu suất của bộ phận đó, đồng thời phối hợp với Quản lý cơ sở để tổ chức hậu kiểm, bắt buộc nhân sự trực sàn phải hoàn thiện làm sạch data trong vòng 24 giờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79fa34f9-cccb-42b9-9999-22c4393013e8','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',41,'image',NULL,'book/31-data-os/b2fc018b-56a7-41cd-b9d1-dcb8272f00c1-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a25337a9-35e2-444d-a067-d0234b204f9a','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',42,'text','**Mantra điều hành cấu trúc dữ liệu:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c64176e-00ad-4a77-a93e-286e6289eb03','279c05ae-2eb2-4767-8213-b65b2e8ff8e1',43,'text','*"Rác nạp vào đầu ống thì rác sẽ chảy ra cuối ống. Một hệ điều hành Data OS mạnh mẽ không chấp nhận những trường dữ liệu mập mờ hay những hồ sơ bệnh nhân bị bỏ trống thông tin. Hãy siết chặt kỷ luật nhập liệu của từng lễ tân, TCO và bác sĩ để biến dữ liệu thành loại tài sản có khả năng sinh lời cao nhất cho phòng khám."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c814540e-84a3-4c07-ac2d-e4ccf3769fb6','31-data-os',NULL,2,'31.4 Data Hygiene - Quy Trình Làm Sạch Và Chống Ô Nhiễm Dữ Liệu Nha Khoa','314-data-hygiene-quy-trinh-lam-sach-va-chong-o-nhiem-du-lieu-nha-khoa',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a09132f2-881f-42fa-a19c-aee01cf6ba3d','c814540e-84a3-4c07-ac2d-e4ccf3769fb6',44,'text','Trong quản trị lâm sàng, một dụng cụ y khoa không được hấp tủy vô trùng sẽ gây nhiễm trùng chéo cho bệnh nhân. Trong quản trị hệ thống cũng vậy, dữ liệu không được làm sạch hằng ngày sẽ gây "nhiễm độc" cho toàn bộ hệ thống báo cáo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('608fa187-1e87-4684-b6a8-093e2ae9d22d','c814540e-84a3-4c07-ac2d-e4ccf3769fb6',45,'text','Bản chất của nguyên lý này rất sòng phẳng: **Rác nạp vào đầu ống thì rác sẽ chảy ra cuối ống (Garbage In, Garbage Out).** Khi nhân sự nhập liệu cẩu thả, sai lệch thông tin, hệ thống Dashboard sẽ trích xuất ra các kết quả sai và trực tiếp dẫn đến những quyết định chiến lược sai lầm của chủ phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('962ccf71-8ee9-44a7-a1f9-43cac2d117d7','31-data-os','c814540e-84a3-4c07-ac2d-e4ccf3769fb6',3,'Ma Trận Phân Tích Lỗi Dữ Liệu Và Hậu Quả Vận Hành','ma-tran-phan-tich-loi-du-lieu-va-hau-qua-van-hanh',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3fc0e36-e6d3-411c-9ae1-d0ef4567926c','962ccf71-8ee9-44a7-a1f9-43cac2d117d7',46,'text','Dưới đây là bản đồ giải phẫu 7 lỗi dữ liệu kinh điển tại các phòng khám nha khoa và cái giá phải trả về mặt tài chính lẫn vận hành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9801ef33-7a2b-4f44-ac54-efb34c795fc7','31-data-os','c814540e-84a3-4c07-ac2d-e4ccf3769fb6',3,'Quy Trình 3 Tầng Vệ Sinh Dữ Liệu Tiêu Chuẩn (Data Cleansing Protocol)','quy-trinh-3-tang-ve-sinh-du-lieu-tieu-chuan-data-cleansing-protocol',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aeb44f5d-50a3-4ea9-b6d5-34887e650d6a','9801ef33-7a2b-4f44-ac54-efb34c795fc7',47,'text','Để đảm bảo dòng máu dữ liệu luôn tinh khiết, phòng khám bắt buộc phải đóng gói hoạt động làm sạch thành một quy trình có tính tuần hoàn, không thể đảo lộn các bước:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('da81eca6-a4f4-4a0f-aae8-e6a29cfc5882','31-data-os','9801ef33-7a2b-4f44-ac54-efb34c795fc7',4,'Kiểm toán ca hằng ngày (Daily Audit):15 phút cuối ca.','kiem-toan-ca-hang-ngay-daily-audit15-phut-cuoi-ca',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0c0943c-283b-43d1-addd-919585a0549b','da81eca6-a4f4-4a0f-aae8-e6a29cfc5882',48,'text','Trước khi bàn giao ca trực, Lễ tân và CSKH bắt buộc phải rà soát toàn bộ lượng hồ sơ phát sinh trong ngày. Đảm bảo 100% hồ sơ mới đều có đầy đủ: Số điện thoại, Nguồn khách, Trạng thái phễu và Nhật ký đầu ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3aed4b66-1add-4b3f-a3ff-67c12204f544','31-data-os','9801ef33-7a2b-4f44-ac54-efb34c795fc7',4,'Quét trùng và Lọc lỗi hằng tuần (Weekly Deep Clean):Họp giao ban tuần.','quet-trung-va-loc-loi-hang-tuan-weekly-deep-cleanhop-giao-ban-tuan',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2eb5d48-38c5-49ee-99de-b7469b9108cf','3aed4b66-1add-4b3f-a3ff-67c12204f544',49,'text','Quản trị viên dữ liệu (Data Owner) sử dụng công cụ quét tự động để phát hiện và gộp các hồ sơ trùng lặp số điện thoại. Sửa lỗi các trường thông tin bị lệch định dạng trước khi dữ liệu được đẩy lên Dashboard tổng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c04c7fac-6d1a-4258-8339-6f85a69274b0','31-data-os','9801ef33-7a2b-4f44-ac54-efb34c795fc7',4,'Khóa sổ dữ liệu hằng tháng (Monthly Data Lock):Ngày 01 đầu tháng kế tiếp.','khoa-so-du-lieu-hang-thang-monthly-data-lockngay-01-au-thang-ke-tiep',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('990ffa64-b76a-4356-8141-86baf9c233b7','c04c7fac-6d1a-4258-8339-6f85a69274b0',50,'text','Sau khi đối soát trùng khớp giữa doanh thu thực thu của Kế toán và sản lượng điều trị chuyên môn của Khối lâm sàng, Data Owner tiến hành "Khóa băng" dữ liệu tháng cũ. Tuyệt đối không cho phép bất kỳ nhân sự nào tự ý sửa đổi số liệu quá khứ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3277f9d4-829c-4de7-a761-de1c7bf1a99d','31-data-os','c814540e-84a3-4c07-ac2d-e4ccf3769fb6',3,'Chỉ Số Tỷ Lệ Nhiễm Bẩn Dữ Liệu (DPR)','chi-so-ty-le-nhiem-ban-du-lieu-dpr',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('353ee0bb-378f-4f9e-ba0c-35d7f92bd75a','3277f9d4-829c-4de7-a761-de1c7bf1a99d',51,'text','Để kiểm soát kỷ luật nhập liệu của bộ máy vận hành sảnh và lâm sàng, Data OS áp dụng chỉ số định lượng **Tỷ lệ nhiễm bẩn dữ liệu (Data Pollution Rate - ****DPR****)** để kiểm toán hệ thống định kỳ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90969db4-ca7a-4df8-9b19-17560c7957d3','3277f9d4-829c-4de7-a761-de1c7bf1a99d',52,'text','DPR (\\%) = \\left( \\frac{\\text{Số hồ sơ phát sinh lỗi hoặc thiếu các trường thông tin bắt buộc}}{\\text{Tổng số hồ sơ được ghi nhận thực tế trên CRM trong chu kỳ}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('99aeece4-a97a-46d4-9baa-332a53120ffc','3277f9d4-829c-4de7-a761-de1c7bf1a99d',53,'text','**Định mức chế tài chất lượng dữ liệu phòng khám:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06bb3017-f785-4ed3-bc49-2c86a186e120','3277f9d4-829c-4de7-a761-de1c7bf1a99d',54,'text','- **Vùng Xanh (An toàn tuyệt đối):** Chỉ số DPR nhỏ hơn 3%. Hệ thống dữ liệu sạch, bảo chứng cho các quyết định đầu tư chính xác.- **Vùng Đỏ (Báo động nguy hiểm):** Chỉ số DPR lớn hơn hoặc bằng 7%. Nguồn nước dữ liệu đã bị ô nhiễm nặng. Mọi chỉ số về ROI, CAC, Close\\ Rate trên Dashboard đều có nguy cơ bị bóp méo. Quản lý cơ sở phải lập tức đình chỉ việc nghiệm thu hiệu suất của bộ phận nhập lỗi, kích hoạt quy trình phạt hành vi và ép toàn đội ngũ thực hiện làm sạch dữ liệu tập trung trong vòng 24 giờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab4aee32-05e2-4ec3-b378-c77c49b638bf','3277f9d4-829c-4de7-a761-de1c7bf1a99d',55,'image',NULL,'book/31-data-os/c0e0a907-6874-4998-9871-1c6818c07e54-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('770c1d0a-c4d4-4cb3-be00-8abd031f6607','3277f9d4-829c-4de7-a761-de1c7bf1a99d',56,'text','**Mantra điều hành Data Hygiene:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d266bb52-f93d-4718-b4c0-273bb4117d3c','3277f9d4-829c-4de7-a761-de1c7bf1a99d',57,'text','*"Dữ liệu bẩn là kẻ thù giấu mặt của lợi nhuận ròng. Hãy duy trì sự nghiêm ngặt và tính vô trùng cho kho dữ liệu của phòng khám giống như cách bạn bảo vệ sự vô trùng của một phòng phẫu thuật Implant. Dữ liệu sạch tạo ra tư duy sạch và những quyết định tăng trưởng thịnh vượng."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7ee1cd63-7a94-4e13-bd9c-1ad7d7df6194','31-data-os',NULL,2,'31.5 Tám Quy Tắc Vàng Nhập Liệu CRM - Đóng Đinh Kỷ Luật Dữ Liệu Đầu Vào','315-tam-quy-tac-vang-nhap-lieu-crm-ong-inh-ky-luat-du-lieu-au-vao',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('edc9a400-9776-4d00-97ce-ba47dd8d9440','7ee1cd63-7a94-4e13-bd9c-1ad7d7df6194',58,'text','Hệ thống CRM (Phần mềm quản trị quan hệ khách hàng) của một phòng khám nha khoa thường bị biến thành một "kho chứa dữ liệu chết" hoặc "bãi rác thông tin" chỉ sau vài tháng vận hành. Nguyên nhân không nằm ở công nghệ, mà nằm ở hành vi của con người. Nếu không có những quy tắc bắt buộc, nhân sự sẽ nhập liệu theo kiểu tùy hứng nhớ thì làm, bận thì bỏ qua.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e89b7fe-ad49-4eb0-84ff-23c4b3b685b4','7ee1cd63-7a94-4e13-bd9c-1ad7d7df6194',59,'text','Để bảo chứng cho dòng dữ liệu luôn sạch và liên thông tuyệt đối, toàn bộ đội ngũ trực sàn (Lễ tân, Chuyên viên tư vấn TCO, Phụ tá, Bác sĩ và CSKH) phải tuân thủ nghiêm ngặt **8 quy tắc đóng đinh** dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f879b47c-1d64-4459-b996-57fd8d1178e4','31-data-os','7ee1cd63-7a94-4e13-bd9c-1ad7d7df6194',3,'Ma Trận Quy Tắc Nhập Liệu Và Mục Tiêu Đối Soát Hệ Thống','ma-tran-quy-tac-nhap-lieu-va-muc-tieu-oi-soat-he-thong',25,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0f343792-8fdf-417b-a740-05fb3f87887f','31-data-os','7ee1cd63-7a94-4e13-bd9c-1ad7d7df6194',3,'Chỉ Số Kỷ Luật Nhập Liệu Thời Gian Thực (CCR)','chi-so-ky-luat-nhap-lieu-thoi-gian-thuc-ccr',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2fe71ea5-0a45-419b-aed2-1bdb2d425471','0f343792-8fdf-417b-a740-05fb3f87887f',60,'text','Để rèn luyện tính kỷ luật tự giác và biến 8 quy tắc này thành bản năng hành động của nhân sự, phòng khám áp dụng chỉ số **Kỷ luật dữ liệu chặng ngắn (CRM Compliance Rate - ****CCR****)** để hậu kiểm ngẫu nhiên hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85230286-3921-42aa-a7cf-86a8adcac148','0f343792-8fdf-417b-a740-05fb3f87887f',61,'text','CCR (\\%) = \\left( \\frac{\\text{Số hồ sơ nhập ĐÚNG và ĐỦ 8 quy tắc vàng}}{\\text{Tổng số hồ sơ phát sinh trong kỳ kiểm toán ngẫu nhiên}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5a2b63c1-7777-45ff-a91c-c773db2f2c75','0f343792-8fdf-417b-a740-05fb3f87887f',62,'text','**Định mức chế tài vận hành Data OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2aac87bc-f626-4776-8ca8-fb404f31a544','0f343792-8fdf-417b-a740-05fb3f87887f',63,'text','- **Ngưỡng an toàn hệ thống:** Chỉ số CCR của toàn cơ sở bắt buộc phải đạt ngưỡng **\\ge 95\\%
**.- **Biện pháp xử lý kỷ luật:** Nếu chỉ số CCR tụt xuống dưới 95%, hệ thống quản trị dữ liệu đang bị buông lỏng. Quản lý cơ sở phải lập tức trích xuất camera và lịch sử thao tác để định danh nhân sự làm sai quy trình. Nhân sự vi phạm sẽ bị trừ trực tiếp vào điểm Hành vi/Thái độ của Khung hiệu suất (*People OS*), đồng thời phải hoàn thành việc chuẩn hóa lại tệ p dữ liệu lỗi trong vòng 24 giờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66b9fbd0-81a2-44a4-8cea-6947a4ee8eea','0f343792-8fdf-417b-a740-05fb3f87887f',64,'image',NULL,'book/31-data-os/4e5ee9ee-ebe1-4882-b17b-433942614e2b-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5321bf3f-ff48-4a99-a144-89694f83957c','0f343792-8fdf-417b-a740-05fb3f87887f',65,'text','**Mantra điều hành kỷ luật CRM:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd8cded4-7a41-4526-b83f-f292d2250d3c','0f343792-8fdf-417b-a740-05fb3f87887f',66,'text','*"Một hệ thống CRM đắt tiền đến đâu cũng sẽ trở nên vô dụng nếu đầu vào của nó là những thông tin rác hoặc những khoảng trống bỏ quên. Hãy coi việc nhập liệu CRM quan trọng và chuẩn xác như việc bạn ghi lại hồ sơ bệnh án lâm sàng. Kỷ luật đầu vào khắt khe là nền móng duy nhất để tạo ra những báo cáo chiến lược sinh lời."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('646a105d-41f7-4095-8a17-d44bf0f1794a','31-data-os',NULL,2,'31.6 Dashboard Data OS - Kiến Trúc Màn Hình Điều Hành Thời Gian Thực Thông Minh','316-dashboard-data-os-kien-truc-man-hinh-ieu-hanh-thoi-gian-thuc-thong-minh',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f027db33-6b49-44e4-aa03-d1bb845c26b8','646a105d-41f7-4095-8a17-d44bf0f1794a',67,'text','Để giải phóng hoàn toàn chủ phòng khám khỏi việc giám sát thủ công mà vẫn nắm trọn quyền kiểm soát vận hành, hệ điều hành **Data OS** thiết lập một màn hình điều hành tổng hợp hiển thị thời gian thực (Real-time Executive Dashboard). Màn hình này được chia tách khoa học thành **8 phân khu chỉ số chiến lược**, đóng vai trò như bảng đồng hồ phi cơ, giúp ban giám đốc phát hiện sớm mọi "bệnh lý vận hành" của phòng khám chỉ qua một ánh nhìn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a88dcdc-7579-4d93-9512-41bf41a761dc','31-data-os','646a105d-41f7-4095-8a17-d44bf0f1794a',3,'Kiến Trúc Tháp Chỉ Số: 8 Phân Khu Tối Cao Trên Dashboard Điều Hành','kien-truc-thap-chi-so-8-phan-khu-toi-cao-tren-dashboard-ieu-hanh',28,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ab152850-8877-45ce-aa7e-48b0ccb0a698','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'Marketing Dashboard (Trung tâm Điều phối Sức kéo)','marketing-dashboard-trung-tam-ieu-phoi-suc-keo',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4a098bc-c2f8-413e-8cde-a8da77b39ada','ab152850-8877-45ce-aa7e-48b0ccb0a698',68,'text','- **Lead theo nguồn:** Truy vết số lượng hồ sơ khách hàng tiềm năng đến từ từng kênh riêng biệt (TikTok, Facebook, Google Maps, Khách vãng lai) để định vị kênh tăng trưởng chủ lực.- **CPL (Cost per Lead):** Chi phí thực tế để mang về một hồ sơ khách hàng tiềm năng, làm màng lọc kiểm soát hiệu suất đốt tiền của đội ngũ quảng cáo.- **Booking Rate:** Tỷ lệ chuyển đổi từ tệp dữ liệu thô sang lịch hẹn thành công trên hệ thống.- **Lead Quality:** Chỉ số phân loại chất lượng data đầu vào (đo bằng tỷ lệ số điện thoại đúng nhu cầu, đúng tệp tài chính).- **Content Performance:** Đo lường sản lượng và hiệu suất chuyển đổi dòng tiền của từng video, bài viết hoặc Case Study lâm sàng được xuất bản.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('96e72d2f-6f56-432c-b405-a1b235aa22ee','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'Sales Dashboard (Trung tâm Chuyển đổi Dòng tiền)','sales-dashboard-trung-tam-chuyen-oi-dong-tien',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ffced688-8287-4498-8965-47ddbfb51cb4','96e72d2f-6f56-432c-b405-a1b235aa22ee',69,'text','- **Booking:** Tổng số lượng lịch hẹn được xác nhận trong chu kỳ.- **Show-up:** Số lượng và tỷ lệ khách hàng thực tế đặt chân đến sảnh chờ phòng khám đúng hẹn.- **Consulted:** Số lượng bệnh nhân đã đi qua bước khám sàng lọc, chụp phim và lên phác đồ điều trị trực tiếp.- **Close Rate:** Tỷ lệ chốt phác đồ thành công (Số ca đồng ý điều trị / Tổng số ca được tư vấn).- **Revenue per Consultant:** Sản lượng doanh thu thực thu chi tiết trên từng chuyên viên tư vấn (TCO), làm thước đo sòng phẳng cho năng lực cá nhân.- **Lost Reason:** Biểu đồ phân tích các lý do từ chối phác đồ (chê giá cao, sợ đau, cần suy nghĩ thêm) để cải tiến kịch bản xử lý từ chối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('919da358-4e31-4aa0-b7c0-678028baf9e5','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'Clinic Dashboard (Trung tâm Công suất Lâm sàng)','clinic-dashboard-trung-tam-cong-suat-lam-sang',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca184afe-d929-4477-9e2d-599810be6bbf','919da358-4e31-4aa0-b7c0-678028baf9e5',70,'text','- **Số ca điều trị:** Tổng sản lượng ca lâm sàng được thực hiện, bóc tách chi tiết theo danh mục dịch vụ (Implant, Chỉnh nha, Sứ, Tổng quát).- **Công suất ghế (Chair Occupancy Rate):** Tỷ lệ thời gian ghế nha có bệnh nhân nằm điều trị thực tế trên tổng giờ mở cửa vận hành.- **Công suất bác sĩ:** Độ tải việc và hiệu suất xử lý ca của từng bác sĩ điều trị để điều phối lịch trực tối ưu.- **Tỷ lệ hoàn thành kế hoạch:** Tốc độ thực hiện phác đồ của bệnh nhân, đảm bảo không bị ngâm ca hoặc trễ tiến độ điều trị.- **Sự cố lâm sàng:** Số lượng các ca phát sinh lỗi kỹ thuật, biến chứng hậu phẫu hoặc quy trình vô trùng bị cảnh báo lỗi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('64818e4c-08b1-4d25-b6d8-fb5432cc9009','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'Patient Experience Dashboard (Trung tâm Bảo chứng Trải nghiệm)','patient-experience-dashboard-trung-tam-bao-chung-trai-nghiem',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23ce0cdb-f73e-4b7e-b55f-5c540cea010c','64818e4c-08b1-4d25-b6d8-fb5432cc9009',71,'text','- **Tỷ lệ hài lòng (Net Promoter Score - NPS):** Chỉ số đo lường mức độ sẵn sàng giới thiệu phòng khám của bệnh nhân cho người thân.- **Số phản hồi tiêu cực:** Số lượng khiếu nại, phàn nàn của khách hàng phát sinh tại sảnh hoặc qua kênh hotline.- **Tỷ lệ CSKH đúng hạn:** Tỷ lệ phần trăm các cuộc gọi theo dõi hậu phẫu (sau nhổ răng, cắm implant) được thực hiện chuẩn xác theo khung giờ quy định (SLA).- **Tỷ lệ khách quay lại (Retention Rate):** Tỷ lệ bệnh nhân cũ tuân thủ lịch hẹn tái khám định kỳ (Recall).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('55c24881-d6c5-4ad0-a38f-f9d0f2c7fa32','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'Review Dashboard (Trung tâm Tài sản Uy tín)','review-dashboard-trung-tam-tai-san-uy-tin',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('27d711f8-8e80-4539-bc61-16a96dc31e11','55c24881-d6c5-4ad0-a38f-f9d0f2c7fa32',72,'text','- **Số review mới:** Sản lượng đánh giá năm sao mới được kích hoạt thành công trên các nền tảng số công khai.- **Rating trung bình:** Điểm số xếp hạng uy tín trung bình của phòng khám (Mục tiêu bắt buộc phải duy trì ở mức lớn hơn hoặc bằng 4.8 sao).- **Review theo bác sĩ:** Thống kê các đánh giá ca ngợi đích danh tay nghề và thái độ của từng bác sĩ điều trị.- **Review theo dịch vụ:** Tỷ lệ phản hồi tích cực phân tách theo từng nhóm dịch vụ chuyên sâu để làm nguyên liệu làm sạch truyền thông.- **Testimonial Collected:** Kho tư liệu hình ảnh, video cảm nhận thực tế của bệnh nhân được bộ phận CSKH đóng gói số hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d9dbccbb-39f7-4b7c-9fec-bb277c9cccb1','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'Referral Dashboard (Trung tâm Bánh đà Hữu cơ)','referral-dashboard-trung-tam-banh-a-huu-co',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('548e4fb8-b052-4a19-a44e-9bdd6c8290f0','d9dbccbb-39f7-4b7c-9fec-bb277c9cccb1',73,'text','- **Số khách giới thiệu:** Tổng số lượng bệnh nhân cũ trung thành tham gia vào mạng lưới "đại sứ thương hiệu".- **Referral Lead:** Số lượng hồ sơ khách hàng mới phát sinh từ nguồn giới thiệu hữu cơ.- **Referral Booking:** Số lượng lịch hẹn đặt thành công từ tệp khách được giới thiệu.- **Referral Revenue:** Tổng dòng tiền mặt thực thu chảy về từ phác đồ của tệp khách Referral.- **Referral Conversion Rate:** Tỷ lệ chốt phác đồ của nguồn giới thiệu (thường cao gấp đôi nguồn quảng cáo trả phí nhờ đòn bẩy lòng tin).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('115b3c98-5ded-407c-9cad-d1047bed67ef','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'Finance Dashboard (Trung tâm Mạch máu Thanh khoản)','finance-dashboard-trung-tam-mach-mau-thanh-khoan',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aadbf9f5-c1f6-4e19-aed0-79fed90357b7','115b3c98-5ded-407c-9cad-d1047bed67ef',74,'text','- **Doanh thu:** Tổng dòng tiền mặt thực thu hằng ngày, hằng tuần và hằng tháng nạp về hệ thống.- **Chi phí:** Biểu đồ bóc tách định phí vận hành phòng khám và biến phí vật liệu đầu ghế nha, chi phí Labo gối đầu.- **Lợi nhuận:** Chỉ số biên lợi nhuận gộp và biên lợi nhuận ròng thời gian thực của cơ sở.- **Dòng tiền (Cash Flow):** Trạng thái số dư tiền mặt tại quỹ an toàn để bảo chứng năng lực thanh khoản tức thời.- **Công nợ:** Theo dõi và phân nhóm các khoản công nợ trả góp của bệnh nhân niềng răng hoặc Implant để lên lịch đôn đốc thu hồi.- **ROI Marketing:** Tỷ lệ hoàn vốn trên chi phí tiếp thị (Doanh thu thuần thu về từ quảng cáo / Chi phí quảng cáo đã chi).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5d854d48-30f3-4a32-b4db-8ffb8547928e','31-data-os','9a88dcdc-7579-4d93-9512-41bf41a761dc',4,'People Dashboard (Trung tâm Động lực Bộ máy)','people-dashboard-trung-tam-ong-luc-bo-may',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2b46c5c-9cd3-4bef-bae6-5b485f6d3f2b','5d854d48-30f3-4a32-b4db-8ffb8547928e',75,'text','- **KPI từng bộ phận:** Chỉ số hoàn thành mục tiêu tổng hợp của khối Sảnh, khối Lâm sàng và khối Tiếp thị.- **Hiệu suất cá nhân:** Bảng xếp hạng năng suất lao động định lượng của từng Phụ tá, Lễ tân và Điều dưỡng trực ca.- **Tỷ lệ nghỉ việc (Turnover Rate):** Chỉ số đo lường sự biến động và độ ổn định của nhân sự trong bộ máy.- **Training Completion:** Tỷ lệ hoàn thành và đạt điểm sát hạch các module đào tạo nội bộ liên tục của nhân sự.- **Điểm đánh giá nội bộ:** Chỉ số chấm điểm chéo 360 độ về thái độ phối hợp liên phòng ban và mức độ tuân thủ văn hóa tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('366d9573-71ce-4a8f-ad6e-035733dafe15','31-data-os','646a105d-41f7-4095-8a17-d44bf0f1794a',3,'Hiệu Suất Khai Thác Công Suất Ghế Nha (CUR)','hieu-suat-khai-thac-cong-suat-ghe-nha-cur',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a924658c-d810-4fb8-b793-482c5c866c0f','366d9573-71ce-4a8f-ad6e-035733dafe15',76,'text','Trong các chỉ số hiển thị trên Clinic Dashboard, chỉ số quyết định năng lực sinh lời tối đa trên một mét vuông diện tích mặt sàn của phòng khám là **Tỷ lệ lấp đầy ghế nha (Chair Utilization Rate - ****CUR****)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25a2c75d-c9d4-4be5-a55e-670b82be20f1','366d9573-71ce-4a8f-ad6e-035733dafe15',77,'text','CUR (\\%) = \\left( \\frac{\\text{Tổng số giờ ghế thực tế có bệnh nhân nằm điều trị}}{\\text{Tổng số giờ mở cửa vận hành tiêu chuẩn của hệ thống ghế}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('efa444f5-b8f0-491e-9bc2-3e488828115e','366d9573-71ce-4a8f-ad6e-035733dafe15',78,'text','**Định mức kiểm toán năng lực vận hành ghế nha:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f8b252c-fa2e-46a5-8b59-4cbc108595cd','366d9573-71ce-4a8f-ad6e-035733dafe15',79,'text','- **Ngưỡng Vùng Xanh (Vận hành tối ưu):** Chỉ số CUR duy trì ổn định ở mức **từ 70% đến 85%**. Bộ máy điều phối lịch hẹn chạy mượt mà, công suất bác sĩ và trợ thủ được khai thác triệt để, dòng tiền sinh ra tối đa trên mỗi đầu ghế.- **Hành động sửa sai:** Nếu chỉ số CUR tụt xuống dưới mức 50%, đây là lời cảnh báo nghiêm trọng: Phòng khám đang lãng phí tài nguyên cố định. Lúc này, chủ phòng khám không được phép đầu tư mở rộng thêm cơ sở, mà phải lập tức nhìn sang *Marketing Dashboard* để siết lại lượng Lead nạp phễu và nhìn sang *Sales Dashboard* để tăng tỷ lệ hẹn gặp (Show-up\\ Rate) nhằm lấp đầy các khoảng trống lịch hẹn ngay trong tuần kế tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7322554-dc6d-4083-80fe-5c2280150ad3','366d9573-71ce-4a8f-ad6e-035733dafe15',80,'text','**Mantra điều hành Dashboard Data OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7133271c-4a01-4075-a1fb-13f6acac9e7d','366d9573-71ce-4a8f-ad6e-035733dafe15',81,'text','*"Một nhà quản trị thông thái không điều hành doanh nghiệp bằng cách nhìn vào gương chiếu hậu hay nghe những lời giải thích chặng cuối. Bảng 8 phân khu Dashboard chính là hệ thống radar thời gian thực — hiển thị rõ nét từng hơi thở vận hành của phòng khám. Hãy để dữ liệu sạch lên tiếng, mọi quyết định chiến lược sẽ tự động đi đúng hướng."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f37a3f18-d186-4b3d-b8f0-4457dfd24728','31-data-os',NULL,2,'31.7 Nhịp Điệu Vận Hành Dữ Liệu Định Kỳ (Data Operating Rhythm)','317-nhip-ieu-van-hanh-du-lieu-inh-ky-data-operating-rhythm',38,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b7ba2d9e-f2e0-49f6-9241-f5e39ce6bffc','31-data-os','f37a3f18-d186-4b3d-b8f0-4457dfd24728',3,'Tư Duy Quản Trị: Xem Dữ Liệu như Theo Dõi Sinh Hiệu?','tu-duy-quan-tri-xem-du-lieu-nhu-theo-doi-sinh-hieu',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3e395f95-238e-493f-8e2c-aac1cda863f4','b7ba2d9e-f2e0-49f6-9241-f5e39ce6bffc',82,'text','Sai lầm phổ biến của các chuỗi phòng khám nha khoa khi làm việc với số liệu là tư duy "cuối tháng xem báo cáo". Nếu một tháng ban điều hành mới mở Dashboard dữ liệu một lần để xem doanh thu, chi phí hay tỷ lệ mất khách, thì lúc đó mọi sự đã rồi. Đó không phải là quản trị, đó là đang đọc "biên bản khám nghiệm tử thi" của một chu kỳ đã qua và hoàn toàn không còn cơ hội sửa sai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1e05502-fdad-4c3a-959e-32d40f3250da','b7ba2d9e-f2e0-49f6-9241-f5e39ce6bffc',83,'text','Trong hệ điều hành **Data OS**, dữ liệu được ví như **chỉ số sinh hiệu (mạch, huyết áp, nhiệt độ)** của cơ thể phòng khám, bắt buộc phải được đo lường, cập nhật và giám sát theo các chu kỳ nhịp đập sinh học đóng cứng. Nhịp điệu vận hành dữ liệu thiết lập tần suất đối soát liên hoàn giữa các khối phòng ban, giúp phát hiện sớm các "khối u" vận hành (như quảng cáo lỗi gây cháy ngân sách, Telesale bỏ quên lịch hẹn, bác sĩ ngâm ca điều trị) để can thiệp xử lý ngay trong ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('70b2b86d-e34a-4960-bd17-2570a66b6563','31-data-os','f37a3f18-d186-4b3d-b8f0-4457dfd24728',3,'Ma Trận Nhịp Điệu Kiểm Toán Và Đồng Bộ Dữ Liệu Tiêu Chuẩn','ma-tran-nhip-ieu-kiem-toan-va-ong-bo-du-lieu-tieu-chuan',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fee1a4fd-c842-4fb9-9118-ed030168e8c3','70b2b86d-e34a-4960-bd17-2570a66b6563',84,'text','Hạ tầng thông tin của phòng khám được duy trì độ tinh khiết và tính chính xác tuyệt đối nhờ vào 4 nhịp vận hành dữ liệu khép kín dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bcdc8b54-4bb3-4cd8-90a0-9b2d932d652d','31-data-os','f37a3f18-d186-4b3d-b8f0-4457dfd24728',3,'Mỏ Neo Toán Học: Chỉ Số Đồng Bộ Và Đúng Hạn Dữ Liệu (DSI)','mo-neo-toan-hoc-chi-so-ong-bo-va-ung-han-du-lieu-dsi',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('379a8128-61c8-43b7-811b-5ae06e382a4b','bcdc8b54-4bb3-4cd8-90a0-9b2d932d652d',85,'text','Để bảo chứng cho việc các phân khu Dashboard hiển thị số liệu luôn "sống" và phản ánh chính xác hơi thở thời gian thực của phòng khám, ban điều hành giám sát chặt chẽ chỉ số **Độ đồng bộ dữ liệu hệ thống (Data Synchronicity Index - ****DSI****)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('003bfa0b-2229-47c6-9894-a2b056b9cc32','bcdc8b54-4bb3-4cd8-90a0-9b2d932d652d',86,'text','DSI (\\%) = \\left( \\frac{\\text{Số điểm chạm dữ liệu được cập nhật đúng hạn SLA quy định trong chu kỳ}}{\\text{Tổng số điểm chạm dữ liệu bắt buộc phải cấu hình trên hệ thống}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1247b37a-b56f-41a4-a010-5bda5c7baefe','bcdc8b54-4bb3-4cd8-90a0-9b2d932d652d',87,'text','- **Ngưỡng an toàn tối cao của Dental Empire:** Chỉ số DSI hằng tuần bắt buộc phải duy trì ở mức **\\ge 98\\%**.- **Hành động sửa sai lập tức:** Nếu chỉ số DSI tụt xuống dưới mức 95%, chứng tỏ bộ máy nhân sự trực sàn đang có dấu hiệu trễ nải, lười nhập liệu hoặc kế toán chậm đối soát. Điều này khiến hệ thống radar Dashboard bị "lệch pha" so với thực địa, trực tiếp làm sai lệch các quyết định điều phối ngân sách quảng cáo hay định biên nhân sự. Quản trị viên dữ liệu (Data\\ Owner) phải phát lệnh cảnh báo hệ thống, yêu cầu Quản lý cơ sở siết lại kỷ luật nhập ca ngay trong vòng 12 giờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('693704d9-60fc-4c4f-a940-944030d3a78c','bcdc8b54-4bb3-4cd8-90a0-9b2d932d652d',88,'image',NULL,'book/31-data-os/40546098-0302-4799-84c9-06624063dd02-img09.png','image.png','image/png','image.png',NULL);
