INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd13e45e-05b0-4aec-98ba-a20ec751318f','2de58472-8ebb-420f-9785-64853bbb5dee',89,'text','Để bảo vệ phòng khám không bị đầu độc bởi thông tin rác và đảm bảo hệ thống Dashboard phản ánh chính xác 100% sinh hiệu vận hành, ban điều hành bắt buộc phải kiểm toán bộ ba mỏ neo toán học này hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f3b61272-8fd3-4ee4-b602-1f8b22d67e89','31-data-os','2de58472-8ebb-420f-9785-64853bbb5dee',5,'Chốt chặn 1 - Độ toàn vẹn dữ liệu hệ thống (DII):','chot-chan-1-o-toan-ven-du-lieu-he-thong-dii',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe4d2907-5a04-4046-a5c6-f6d7b274714b','f3b61272-8fd3-4ee4-b602-1f8b22d67e89',90,'text','- DII \\ge 98\\%
- 100% hồ sơ bệnh nhân phát sinh giao dịch thực tế trên CRM phải được điền đầy đủ, chính xác các trường thông tin quy chuẩn, không chấp nhận khoảng trống mập mờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2c1b4207-6a65-4aad-a16c-67b98ea5225d','31-data-os','2de58472-8ebb-420f-9785-64853bbb5dee',5,'Chốt chặn 2 - Tỷ lệ thất thoát dữ liệu toàn phễu (FAL):','chot-chan-2-ty-le-that-thoat-du-lieu-toan-pheu-fal',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b97519f9-4c65-4b6f-ac7a-5e409b1fe79c','2c1b4207-6a65-4aad-a16c-67b98ea5225d',91,'text','- FAL < 5\\%
- Kiểm soát nghiêm ngặt đường ống trích xuất dữ liệu liên thông; triệt tiêu hoàn toàn hiện tượng rò rỉ data, mất dấu vết bệnh nhân hoặc nhân sự tự ý xóa thông tin chưa qua phê duyệt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('adeb1928-cde0-4a44-b2a3-b0bcdb04b90a','31-data-os','2de58472-8ebb-420f-9785-64853bbb5dee',5,'Chốt chặn 3 - Độ đồng bộ dữ liệu thời gian thực (DSI):','chot-chan-3-o-ong-bo-du-lieu-thoi-gian-thuc-dsi',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8bb9da05-bdd2-448d-9b37-caa8dcfe31f1','adeb1928-cde0-4a44-b2a3-b0bcdb04b90a',92,'text','- DSI \\ge 98\\%
- Bảo chứng cho mạch máu thông tin luôn sống hằng ngày. Mọi biến động trạng thái điều trị và dòng tiền mặt tại sảnh phải được liên thông lên Dashboard điều hành ngay trong ca trực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('98f8fc8a-3c7d-4ef3-81bf-2c49969fbf4c','31-data-os','f37a3f18-d186-4b3d-b8f0-4457dfd24728',3,'Sự Chuyển Dịch Vị Thế Của Chủ Phòng Khám Nha Khoa','su-chuyen-dich-vi-the-cua-chu-phong-kham-nha-khoa',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9abf400e-88ae-40c5-91d4-d168199f48a2','98f8fc8a-3c7d-4ef3-81bf-2c49969fbf4c',93,'text','Khi 8 phân khu Dashboard của Data OS được kích hoạt liên thông với Quy tắc nhập liệu và Nhịp điệu đối soát định kỳ, tư duy điều hành của doanh nghiệp sẽ đạt đến trạng thái minh triết:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73baf2a6-8b86-46a9-8504-d465370600ae','98f8fc8a-3c7d-4ef3-81bf-2c49969fbf4c',94,'image',NULL,'book/31-data-os/a86454ac-48c9-443b-bf33-cf23c4251ee2-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8a63bfd-8932-4c20-bc54-6f4d1b21908d','98f8fc8a-3c7d-4ef3-81bf-2c49969fbf4c',95,'text','Người chủ sẽ không còn bị che mắt bởi các báo cáo định tính hoa mỹ hay những lý do ngụy biện chặng cuối. Mỗi quyết định mở rộng quy mô, đổ thêm ngân sách tiếp thị hay tái cấu trúc lương thưởng đều được đưa ra dựa trên những bằng chứng thực chứng sắc nét như một bản phim chụp X-quang toàn cảnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7b4e070-0826-43e4-9831-f3eeb697e8a6','98f8fc8a-3c7d-4ef3-81bf-2c49969fbf4c',96,'text','**Mantra tối cao khóa phân hệ Data OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8c6fdea-828e-45a7-ba48-0668a4da0a98','98f8fc8a-3c7d-4ef3-81bf-2c49969fbf4c',97,'text','*"Trong phòng phẫu thuật lâm sàng, chúng ta chỉ tin vào chỉ số sinh hiệu và phim chụp CT Cone Beam để hạ dao điều trị. Trong phòng điều hành nha khoa cũng vậy, hãy tuyệt đối trung thành với dữ liệu sạch. Con người có thể thỏa hiệp với hiệu suất, nhưng các con số thực chứng trên Dashboard thì không bao giờ biết nói dối. Hãy để dữ liệu dẫn đường cho sự thịnh vượng bền vững."*',NULL,NULL,NULL,NULL,NULL);
